        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(3)
        result = sock.connect_ex((host, port))
        sock.close()

        if result == 0:
            # Port is open, try HTTP request
            try:
                http_result = subprocess.run(
                    ["curl", "-s", "-w", "\n%{http_code}", "--max-time", "5", f"http://{host}:{port}"],
                    capture_output=True,
                    text=True,
                    timeout=10
                )
