repo = "/home/openclaw/.hermes/hermes-agent"
venv_pip = os.path.join(repo, "venv", "bin", "pip")
hermes_bin = os.path.join(repo, "venv", "bin", "hermes")

def run(cmd, cwd=None):
    try:
        result = subprocess.run(cmd, shell=True, cwd=cwd or repo, capture_output=True, text=True, timeout=60)
        return {"cmd": cmd, "stdout": result.stdout.strip(), "stderr": result.stderr.strip(), "returncode": result.returncode}
    except Exception as e:
        return {"cmd": cmd, "error": str(e)}

out = {}

# 1. Hermes version (pre-update)
if os.path.exists(hermes_bin):
    v = subprocess.run([hermes_bin, "--version"], capture_output=True, text=True)
    if v.returncode != 0:
        v = subprocess.run([hermes_bin, "-v"], capture_output=True, text=True)
    out["pre_version"] = v.stdout.strip() if v.returncode==0 else f"error: {v.stderr.strip()}"
else:
    out["pre_version"] = "binary not found"

# 2. Git checks
if os.path.isdir(os.path.join(repo, ".git")):
    out["git"] = {}
    # Status porcelain for cleanliness
    clean_check = run("git status --porcelain")
    out["git"]["clean"] = clean_check["stdout"] == ""
    out["git"]["porcelain"] = clean_check["stdout"]
    # Fetch
    fetch = run("git fetch")
    out["git"]["fetch"] = fetch["stdout"] or fetch["stderr"]
    # Count behind
    behind_cmd = "git rev-list --count HEAD..@{u}"
    behind = run(behind_cmd)
    if behind["returncode"] == 0:
        out["git"]["behind_count"] = int(behind["stdout"]) if behind["stdout"].isdigit() else None
    else:
        out["git"]["behind_count"] = None
        out["git"]["behind_error"] = behind["stderr"]
    # Pull if behind and clean
    pulled = None
    if out["git"]["clean"] and out["git"]["behind_count"] and out["git"]["behind_count"] > 0:
        pull = run("git pull")
        pulled = pull["returncode"] == 0
        out["git"]["pull"] = {"success": pulled, "stdout": pull["stdout"], "stderr": pull["stderr"]}
    else:
        out["git"]["pull"] = {"performed": False, "reason": "not clean or not behind"}
    # Post-pull version
    if os.path.exists(hermes_bin):
        v2 = subprocess.run([hermes_bin, "--version"], capture_output=True, text=True)
        if v2.returncode != 0:
            v2 = subprocess.run([hermes_bin, "-v"], capture_output=True, text=True)
        out["post_version"] = v2.stdout.strip() if v2.returncode==0 else f"error: {v2.stderr.strip()}"
    else:
        out["post_version"] = "binary not found"
    # Dependency install if requirements exist
    req_path = os.path.join(repo, "requirements.txt")
    if os.path.exists(req_path):
        pip_inst = run(f'"{venv_pip}" install -r "{req_path}"')
        out["pip_requirements"] = {"success": pip_inst["returncode"]==0, "stdout": pip_inst["stdout"], "stderr": pip_inst["stderr"]}
    else:
        out["pip_requirements"] = {"skipped": True, "reason": "no requirements.txt"}
else:
    out["git"] = "Not a git repository"
    # Could try pip upgrade? But not now.

print(json.dumps(out, indent=2))"}

